import React, { useState, useEffect } from 'react';
import { toast } from 'react-toastify';
import { getTransactions, getFilteredTransactions, addTransaction, deleteTransaction, getTotalSum, getBudgetAnalyses } from '../services/api';
import Card from './Card';
import ExpenseChart from './ExpenseChart';
import CsvImport from './CsvImport';
import AddTransactionModal from './AddTransactionModal';
import SmartInsights from './SmartInsights';

const Dashboard = ({ onLogout }) => {
  const [transactions, setTransactions] = useState([]);
  const [totalBalance, setTotalBalance] = useState(0);
  const [budgetAnalyses, setBudgetAnalyses] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [formData, setFormData] = useState({
    description: '',
    amount: '',
    date: new Date().toISOString().split('T')[0],
    category: 'Food',
  });

  // Filter state
  const [filters, setFilters] = useState({
    month: null,
    year: null,
    category: '',
  });

  // Fetch transactions and total on component mount
  useEffect(() => {
    fetchDashboardData();
  }, []);

  const defaultUserId = process.env.REACT_APP_USER_ID || 'default-user';

  const fetchDashboardData = async () => {
    setLoading(true);
    setError(null);
    try {
      const [transactionsData, totalData, budgetsData] = await Promise.all([
        getTransactions(),
        getTotalSum(),
        getBudgetAnalyses(defaultUserId),
      ]);
      setTransactions(transactionsData);
      setTotalBalance(totalData);
      setBudgetAnalyses(budgetsData);
    } catch (err) {
      setError('Failed to fetch dashboard data. Make sure the backend is running.');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  // Handle filter changes
  const handleFilterChange = async (newFilters) => {
    setFilters(newFilters);
    setLoading(true);
    setError(null);
    try {
      const filteredData = await getFilteredTransactions(newFilters);
      setTransactions(filteredData);
    } catch (err) {
      setError('Failed to fetch filtered transactions');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  // Reset filters
  const resetFilters = async () => {
    setFilters({
      month: null,
      year: null,
      category: '',
    });
    setLoading(true);
    setError(null);
    try {
      const allTransactions = await getTransactions();
      setTransactions(allTransactions);
    } catch (err) {
      setError('Failed to reset filters');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value,
    });
  };

  const handleSubmit = async (formDataToSubmit) => {
    if (!formDataToSubmit.description || !formDataToSubmit.amount || !formDataToSubmit.date || !formDataToSubmit.category) {
      toast.error('Please fill in all fields');
      return;
    }

    try {
      const newTransaction = await addTransaction({
        ...formDataToSubmit,
        amount: parseFloat(formDataToSubmit.amount),
      });

      setTransactions([newTransaction, ...transactions]);
      setTotalBalance(totalBalance + parseFloat(formDataToSubmit.amount));
      
      // Close modal and show success toast
      setIsModalOpen(false);
      toast.success(`✓ Transaction added: $${parseFloat(formDataToSubmit.amount).toFixed(2)}`);
      setError(null);
    } catch (err) {
      toast.error('Failed to add transaction');
      console.error(err);
    }
  };

  const handleDelete = async (id) => {
    try {
      const transactionToDelete = transactions.find((t) => t.id === id);
      await deleteTransaction(id);
      setTransactions(transactions.filter((t) => t.id !== id));

      if (transactionToDelete) {
        setTotalBalance(totalBalance - transactionToDelete.amount);
        toast.success(`✓ Transaction deleted: -$${transactionToDelete.amount.toFixed(2)}`);
      }

      setError(null);
    } catch (err) {
      toast.error('Failed to delete transaction');
      console.error(err);
    }
  };

  const handleImportSuccess = async (importResult) => {
    // Refresh dashboard data after successful import
    if (importResult.successfulRecords > 0) {
      toast.success(`✓ Successfully imported ${importResult.successfulRecords} transaction${importResult.successfulRecords !== 1 ? 's' : ''}!`);
      fetchDashboardData();
    }
  };

  const categories = [
    { label: 'Food & Dining', value: 'Food' },
    { label: 'Transport', value: 'Transport' },
    { label: 'Entertainment', value: 'Entertainment' },
    { label: 'Utilities', value: 'Utilities' },
    { label: 'Shopping', value: 'Shopping' },
    { label: 'Healthcare', value: 'Healthcare' },
    { label: 'Other', value: 'Other' },
  ];

  const getCategoryEmoji = (category) => {
    const emojiMap = {
      Food: '🍔',
      Transport: '🚗',
      Entertainment: '🎬',
      Utilities: '💡',
      Shopping: '🛍️',
      Healthcare: '🏥',
      Other: '📌',
    };
    return emojiMap[category] || '📌';
  };

  const getCurrentYear = new Date().getFullYear();
  const monthNames = [
    'January', 'February', 'March', 'April', 'May', 'June',
    'July', 'August', 'September', 'October', 'November', 'December'
  ];

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100 p-6">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div className="mb-8 flex justify-between items-center">
          <div>
            <h1 className="text-4xl font-bold text-gray-900 mb-2">💰 Finance Dashboard</h1>
            <p className="text-gray-600">Manage and track your personal finances</p>
          </div>
          <button
            onClick={onLogout}
            className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 transition font-semibold"
          >
            Logout
          </button>
        </div>

        <SmartInsights transactions={transactions} budgetAnalyses={budgetAnalyses} />

        {/* Error Message */}
        {error && (
          <div className="mb-6 p-4 bg-red-100 border border-red-400 text-red-700 rounded-lg">
            <p className="font-semibold">{error}</p>
          </div>
        )}

        {/* Summary Section */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
          <Card
            title="Total Balance"
            value={`$${totalBalance.toFixed(2)}`}
            icon="💳"
            gradient="from-blue-600 to-indigo-600"
          />
          <Card
            title="Total Transactions"
            value={transactions.length}
            icon="📊"
            gradient="from-purple-600 to-pink-600"
          />
          <Card
            title="Average Spend"
            value={`$${
              transactions.length > 0
                ? (totalBalance / transactions.length).toFixed(2)
                : '0.00'
            }`}
            icon="📈"
            gradient="from-green-600 to-teal-600"
          />
        </div>

        {/* Filter Section */}
        <div className="card bg-white mb-8">
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-2xl font-bold text-gray-900">🔍 Filter Transactions</h2>
            {(filters.month || filters.year || filters.category) && (
              <button
                onClick={resetFilters}
                className="px-4 py-2 bg-gray-200 text-gray-800 rounded-lg hover:bg-gray-300 transition font-semibold"
              >
                Clear Filters
              </button>
            )}
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {/* Category Filter */}
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">
                Category
              </label>
              <select
                value={filters.category}
                onChange={(e) => handleFilterChange({
                  ...filters,
                  category: e.target.value,
                })}
                className="input-field w-full"
              >
                <option value="">All Categories</option>
                {categories.map((cat) => (
                  <option key={cat.value} value={cat.value}>
                    {cat.label}
                  </option>
                ))}
              </select>
            </div>

            {/* Month Filter */}
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">
                Month
              </label>
              <select
                value={filters.month || ''}
                onChange={(e) => handleFilterChange({
                  ...filters,
                  month: e.target.value ? parseInt(e.target.value) : null,
                })}
                className="input-field w-full"
              >
                <option value="">All Months</option>
                {monthNames.map((month, index) => (
                  <option key={index + 1} value={index + 1}>
                    {month}
                  </option>
                ))}
              </select>
            </div>

            {/* Year Filter */}
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">
                Year
              </label>
              <select
                value={filters.year || ''}
                onChange={(e) => handleFilterChange({
                  ...filters,
                  year: e.target.value ? parseInt(e.target.value) : null,
                })}
                className="input-field w-full"
              >
                <option value="">All Years</option>
                {[getCurrentYear, getCurrentYear - 1, getCurrentYear - 2].map((year) => (
                  <option key={year} value={year}>
                    {year}
                  </option>
                ))}
              </select>
            </div>
          </div>

          {/* Active Filters Display */}
          {(filters.month || filters.year || filters.category) && (
            <div className="mt-4 pt-4 border-t border-gray-200 flex flex-wrap gap-2">
              {filters.category && (
                <span className="inline-flex items-center px-3 py-1 bg-blue-100 text-blue-800 rounded-full text-sm font-semibold">
                  Category: {categories.find(c => c.value === filters.category)?.label}
                  <button
                    onClick={() => handleFilterChange({ ...filters, category: '' })}
                    className="ml-2 text-blue-600 hover:text-blue-800"
                  >
                    ✕
                  </button>
                </span>
              )}
              {filters.month && (
                <span className="inline-flex items-center px-3 py-1 bg-green-100 text-green-800 rounded-full text-sm font-semibold">
                  Month: {monthNames[filters.month - 1]}
                  <button
                    onClick={() => handleFilterChange({ ...filters, month: null })}
                    className="ml-2 text-green-600 hover:text-green-800"
                  >
                    ✕
                  </button>
                </span>
              )}
              {filters.year && (
                <span className="inline-flex items-center px-3 py-1 bg-purple-100 text-purple-800 rounded-full text-sm font-semibold">
                  Year: {filters.year}
                  <button
                    onClick={() => handleFilterChange({ ...filters, year: null })}
                    className="ml-2 text-purple-600 hover:text-purple-800"
                  >
                    ✕
                  </button>
                </span>
              )}
            </div>
          )}
        </div>

        <div className="flex justify-center mb-8">
          <button
            onClick={() => setIsModalOpen(true)}
            className="btn-primary px-8 py-3 text-lg font-semibold rounded-lg hover:shadow-lg transition-shadow"
          >
            + Add Transaction
          </button>
        </div>

        <div className="grid grid-cols-1 gap-8">
          {/* Transactions Table */}
          <div className="lg:col-span-2">
            <div className="card bg-white">
              <h2 className="text-2xl font-bold text-gray-900 mb-6">
                {filters.month || filters.year || filters.category
                  ? 'Filtered Transactions'
                  : 'Recent Transactions'}
              </h2>

              {loading ? (
                <div className="text-center py-12">
                  <div className="inline-block">
                    <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-500 mb-4"></div>
                    <p className="text-gray-600 font-semibold">Loading transactions...</p>
                  </div>
                </div>
              ) : transactions.length === 0 ? (
                <div className="text-center py-8">
                  <p className="text-gray-600">
                    {filters.month || filters.year || filters.category
                      ? 'No transactions found for the selected filters'
                      : 'No transactions yet. Add one to get started!'}
                  </p>
                </div>
              ) : (
                <div className="overflow-x-auto">
                  <table className="w-full text-sm">
                    <thead className="bg-gray-50 border-b border-gray-200">
                      <tr>
                        <th className="px-6 py-3 text-left font-semibold text-gray-700">Date</th>
                        <th className="px-6 py-3 text-left font-semibold text-gray-700">Description</th>
                        <th className="px-6 py-3 text-left font-semibold text-gray-700">Category</th>
                        <th className="px-6 py-3 text-right font-semibold text-gray-700">Amount</th>
                        <th className="px-6 py-3 text-center font-semibold text-gray-700">Action</th>
                      </tr>
                    </thead>
                    <tbody>
                      {transactions.map((transaction) => (
                        <tr key={transaction.id} className="border-b border-gray-200 table-row-hover">
                          <td className="px-6 py-4 whitespace-nowrap text-gray-600">
                            {new Date(transaction.date).toLocaleDateString('en-US', {
                              year: 'numeric',
                              month: 'short',
                              day: 'numeric',
                            })}
                          </td>
                          <td className="px-6 py-4 text-gray-800 font-medium">
                            {transaction.description}
                          </td>
                          <td className="px-6 py-4">
                            <span className="inline-flex items-center px-3 py-1 rounded-full text-sm font-semibold bg-blue-100 text-blue-800">
                              {getCategoryEmoji(transaction.category)} {transaction.category}
                            </span>
                          </td>
                          <td className="px-6 py-4 text-right font-bold text-blue-600">
                            ${transaction.amount.toFixed(2)}
                          </td>
                          <td className="px-6 py-4 text-center">
                            <button
                              onClick={() => handleDelete(transaction.id)}
                              className="btn-danger text-sm"
                            >
                              Delete
                            </button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* CSV Import Section */}
        <div className="mb-8">
          <CsvImport onImportSuccess={handleImportSuccess} />
        </div>

        {/* Expense Chart Section */}
        <div className="mb-8">
          <ExpenseChart transactions={transactions} />
        </div>

        {/* Add Transaction Modal */}
        <AddTransactionModal 
          isOpen={isModalOpen} 
          onClose={() => setIsModalOpen(false)} 
          onSubmit={handleSubmit}
          categories={categories}
        />
      </div>
    </div>
  );
};

export default Dashboard;
